class Solution {
public:
    int getMaxRepetitions(string s1, int n1, string s2, int n2) {
        int m = s2.size();
        vector<int> dp(m + 1, 0);
        for (int i = 1; i <= m; i++) {
            int count = 0;
            int j = 0;
            for (int k = 0; k < n1 * s1.size(); k++) {
                if (s1[k % s1.size()] == s2[(i - 1) % m]) {
                    if ((i - 1) % m == m - 1) {
                        count++;
                    }
                }
            }
            dp[i] = count;
        }
        return dp[m] / n2;
    }
};

